import{_ as r,o as t,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"48. Rest Period After Overtime Recall Ten Hour Break","description":"","frontmatter":{"title":"48. Rest Period After Overtime Recall Ten Hour Break","eba":"Biomedical Engineers 2025-2028","topics":["hours","overtime","shift-work","rosters"]},"headers":[],"relativePath":"ebas/biomedical-engineers/hours-of-work/48-rest-period-after-overtime-recall-ten-hour-break.md","filePath":"ebas/biomedical-engineers/hours-of-work/48-rest-period-after-overtime-recall-ten-hour-break.md"}'),n={name:"ebas/biomedical-engineers/hours-of-work/48-rest-period-after-overtime-recall-ten-hour-break.md"};function s(i,e,l,c,h,u){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_48-rest-period-after-overtime-recall-ten-hour-break" tabindex="-1">48. Rest Period After Overtime Recall Ten Hour Break <a class="header-anchor" href="#_48-rest-period-after-overtime-recall-ten-hour-break" aria-label="Permalink to &quot;48. Rest Period After Overtime Recall Ten Hour Break&quot;">​</a></h1><p><strong>48.1</strong> When overtime, including recall (but excluding recall – no return to workplace) is necessary, it should be arranged so that Employees have at least 10 consecutive hours off duty between that work and the next successive shift.</p><p><strong>48.2</strong> An Employee who works so much overtime or recall work (excluding recall – no return to workplace) between the termination of their last previous rostered ordinary hours of duty and the commencement of their next succeeding rostered period of duty such that they would not have had at least 10 consecutive hours off duty between the completion of overtime/recall and the commencement of the next rostered shifts, then subject to this clause, they shall be released after completion of such overtime or recall work until they have had 10 consecutive hours off duty without loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>48.3</strong> If an Employee is required by the Employer to resume or to continue to work without having had 10 consecutive hours off duty they will be paid at the rate of double time until they have been released from duty for such rest period and they shall then be entitled to 10 consecutive hours off duty without loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>48.4</strong> Recall – no return to workplace</p><p><strong>(a)</strong> Where an Employee:</p><p><strong>(i)</strong> performs Recall – no return to workplace on the instructions of the Employer, and</p><p><strong>(ii)</strong> does not have at least 10 consecutive hours off duty between the termination of ordinary hours on one day and the commencement of ordinary hours on the next day, the Employer will consult with the Employee about measures to mitigate any occupational health and safety risks associated with the Employee commencing their shift at the normal time.</p><p><strong>(b)</strong> Measures to mitigate risks may include:</p><p><strong>(i)</strong> Commencing work after receiving 10 consecutive hours off duty (or another agreed time period),</p><p><strong>(ii)</strong> Finishing work at an earlier time, or</p><p><strong>(iii)</strong> Taking a longer lunch break, save that an Employee will receive pay for ordinary hours occurring during any absence.</p><p>Plain language terms: OT, extra hours, double time.</p>',13)])])}const p=r(n,[["render",s]]);export{m as __pageData,p as default};
